import { describe, expect, it } from 'vitest';
import {
  THOTH_ERASURE_LEDGER_FRAME_KIND,
  THOTH_ERASURE_THEOREM_REFS,
  auditThothErasureTransition,
  emptyThothMemory,
  encodeThothErasureLedgerFrame,
  eraseThothMemory,
  isThothErasureLedgerFrame,
  renderThothErasureLedgerPromptContext,
  thothErasureLedgerMetrics,
  thothErasureLineage,
  totalEverWritten,
  writeThothMemory,
} from '../src/thoth-erasure-ledger';
import type { ThothLedgeredMemory } from '../src/thoth-erasure-ledger';

function seededMemory(): ThothLedgeredMemory {
  let memory = emptyThothMemory();
  memory = writeThothMemory(memory, { tick: 1, payload: 'the oath ledger' });
  memory = writeThothMemory(memory, { tick: 2, payload: 'the fold phase' });
  memory = writeThothMemory(memory, { tick: 3, payload: 'the ken bound' });
  return memory;
}

describe('Thoth erasure ledger', () => {
  it('write grows the conservation quantity by exactly one', () => {
    const before = seededMemory();
    const after = writeThothMemory(before, { tick: 4, payload: 'new' });
    expect(totalEverWritten(after)).toBe(totalEverWritten(before) + 1);
    expect(auditThothErasureTransition(totalEverWritten(before), after)).toBe(
      'grew',
    );
  });

  it('lawful erasure conserves the total and leaves a lineage record', () => {
    const before = seededMemory();
    const after = eraseThothMemory(before, 1, 'consolidation', 9);

    expect(totalEverWritten(after)).toBe(totalEverWritten(before));
    expect(auditThothErasureTransition(totalEverWritten(before), after)).toBe(
      'conserved',
    );
    expect(after.live.map((entry) => entry.tick)).toEqual([1, 3]);

    const lineage = thothErasureLineage(after);
    expect(lineage).toHaveLength(1);
    expect(lineage[0]).toEqual({
      originalTick: 2,
      payloadEcho: 'the fold phase',
      reason: 'consolidation',
      erasedAtTick: 9,
    });
  });

  it('out-of-range erasure is the identity, as in the Lean carrier', () => {
    const before = seededMemory();
    expect(eraseThothMemory(before, 99, 'retention', 9)).toBe(before);
  });

  it('silent erasure is detected by the conservation audit', () => {
    const before = seededMemory();
    const silentlyEdited: ThothLedgeredMemory = {
      live: before.live.slice(0, 2),
      erased: before.erased,
    };
    expect(
      auditThothErasureTransition(totalEverWritten(before), silentlyEdited),
    ).toBe('silent-erasure-detected');
  });

  it('encodes a non-authoritative ledger frame citing the detection theorem', () => {
    const memory = eraseThothMemory(seededMemory(), 0, 'operator', 11);
    const metrics = thothErasureLedgerMetrics(memory, 'conserved');
    expect(metrics.liveCount).toBe(2);
    expect(metrics.erasedCount).toBe(1);
    expect(metrics.totalEverWritten).toBe(3);
    expect(metrics.lineageTotal).toBe(true);

    const frame = encodeThothErasureLedgerFrame('thoth-host', metrics);
    expect(isThothErasureLedgerFrame(frame)).toBe(true);
    expect(frame.mediaType.Abstract).toBe(THOTH_ERASURE_LEDGER_FRAME_KIND);
    expect(frame.deficit).toBe(0);
    expect(frame.attributes.audit_verdict).toBe('conserved');
    expect(frame.attributes.detection_theorem_ref).toBe(
      THOTH_ERASURE_THEOREM_REFS.detection,
    );

    const violatedMetrics = thothErasureLedgerMetrics(
      memory,
      'silent-erasure-detected',
    );
    expect(
      encodeThothErasureLedgerFrame('thoth-host', violatedMetrics).deficit,
    ).toBe(1);

    const context = renderThothErasureLedgerPromptContext(metrics);
    expect(context).toContain('kind=thoth.erasure-ledger.v1');
    expect(context).toContain('Memory edited outside the ledger is inadmissible');
  });
});
